#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>
#include <omp.h>

#include "kmeans.h"

// Host-side memory allocations that were previously for device
int    *membership_new;                 /* newly assignment membership */
float  *block_new_centers;              /* sum of points in a cluster (per block) */

/* -------------- allocateMemory() ------------------- */
/* allocate device memory, calculate number of blocks and threads, and invert the data array */
// This function is largely removed as it was CUDA-specific.
// Memory allocation for host-side structures remains.
void allocateMemory(int npoints, int nfeatures, int nclusters)
{
    /* allocate memory for membership_new[] and initialize to -1 (host) */
    membership_new = (int*) malloc(npoints * sizeof(int));
    if (membership_new == NULL) {
        perror("Failed to allocate memory for membership_new");
        exit(EXIT_FAILURE);
    }
    for(int i=0; i < npoints; i++) {
        membership_new[i] = -1;
    }

    /* allocate memory for block_new_centers[] (host) */
    block_new_centers = (float *) malloc(nclusters * nfeatures * sizeof(float));
    if (block_new_centers == NULL) {
        perror("Failed to allocate memory for block_new_centers");
        exit(EXIT_FAILURE);
    }
}
/* -------------- allocateMemory() end ------------------- */

/* -------------- deallocateMemory() ------------------- */
/* free host and device memory */
void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
}
/* -------------- deallocateMemory() end ------------------- */


/* ------------------- kmeansCuda() ------------------------ */
// Renamed to kmeans_clustering to reflect the target API
// and to avoid conflict with the original CUDA version if it were in the same scope.
// In this translation, it replaces the CUDA version's functionality.
float **kmeans_clustering(float  **feature,             /* in: [npoints][nfeatures] */
                          int      nfeatures,           /* number of attributes for each point */
                          int      npoints,             /* number of data points */
                          int      nclusters,           /* number of clusters */
                          float    threshold,           /* loop terminating factor */
                          int     *membership           /* which cluster the point belongs to */
                         )
{
    int delta = 0;      /* if point has moved */
    int i, j;           /* counters */
    float **new_centers; /* coordinates of cluster centers */

    // Allocate memory for new cluster centers
    new_centers = (float **) malloc(nclusters * sizeof(float*));
    if (new_centers == NULL) {
        perror("Failed to allocate memory for new_centers");
        exit(EXIT_FAILURE);
    }
    for (i = 0; i < nclusters; i++) {
        new_centers[i] = (float *) malloc(nfeatures * sizeof(float));
        if (new_centers[i] == NULL) {
            perror("Failed to allocate memory for new_centers[i]");
            exit(EXIT_FAILURE);
        }
        memset(new_centers[i], 0, nfeatures * sizeof(float));
    }

    // Initialize cluster centers (e.g., randomly select points)
    // This part is crucial for K-means and was likely handled by CUDA kernels or setup.
    // For OpenMP, we'll perform it on the host.
    // A simple initialization: pick the first 'nclusters' points as initial centers.
    // A more robust initialization (like random selection or k-means++) would be better.
    if (nclusters > npoints) {
        fprintf(stderr, "Error: Number of clusters cannot be greater than number of points.\n");
        exit(EXIT_FAILURE);
    }
    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++) {
            new_centers[i][j] = feature[i][j];
        }
    }

    // Main K-means loop
    int loop = 0;
    do {
        delta = 0; // Reset delta for each iteration

        // Reset block_new_centers (which will be used for summation)
        memset(block_new_centers, 0, nclusters * nfeatures * sizeof(float));
        int *new_centers_len = (int*) malloc(nclusters * sizeof(int));
        if (new_centers_len == NULL) {
            perror("Failed to allocate memory for new_centers_len");
            exit(EXIT_FAILURE);
        }
        for(i=0; i<nclusters; ++i) {
            new_centers_len[i] = 0;
        }

        // Assign points to the nearest cluster center and sum up points per cluster
        #pragma omp parallel shared(feature, membership, membership_new, new_centers, new_centers_len, block_new_centers, delta) private(i, j)
        {
            // Temporary storage for each thread's contribution to new centers and counts
            float *thread_new_centers = (float*) calloc(nclusters * nfeatures, sizeof(float));
            if (thread_new_centers == NULL) {
                perror("Failed to allocate memory for thread_new_centers");
                // In a parallel region, exiting might be tricky. Consider setting an error flag.
                // For simplicity here, we'll assume allocation succeeds or the program terminates.
                exit(EXIT_FAILURE);
            }
            int *thread_new_centers_len = (int*) calloc(nclusters, sizeof(int));
            if (thread_new_centers_len == NULL) {
                perror("Failed to allocate memory for thread_new_centers_len");
                exit(EXIT_FAILURE);
            }
            int thread_delta = 0;

            #pragma omp for schedule(static) nowait
            for (i = 0; i < npoints; i++) {
                int cluster_id = -1;
                float min_dist = FLT_MAX;

                // Find the nearest cluster center
                for (j = 0; j < nclusters; j++) {
                    float dist = 0.0f;
                    for (int k = 0; k < nfeatures; k++) {
                        float diff = feature[i][k] - new_centers[j][k];
                        dist += diff * diff;
                    }

                    if (dist < min_dist) {
                        min_dist = dist;
                        cluster_id = j;
                    }
                }

                // Assign point to the nearest cluster
                membership_new[i] = cluster_id;

                // Accumulate sums for new cluster centers and count points per cluster
                if (cluster_id != -1) {
                    thread_new_centers_len[cluster_id]++;
                    for (j = 0; j < nfeatures; j++) {
                        thread_new_centers[cluster_id * nfeatures + j] += feature[i][j];
                    }
                }

                // Check if membership has changed
                if (membership[i] != membership_new[i]) {
                    thread_delta++;
                }
            }

            // Reduce thread-local sums to global sums
            #pragma omp critical
            {
                delta += thread_delta;
                for (j = 0; j < nclusters; j++) {
                    new_centers_len[j] += thread_new_centers_len[j];
                    for (int k = 0; k < nfeatures; k++) {
                        block_new_centers[j * nfeatures + k] += thread_new_centers[j * nfeatures + k];
                    }
                }
            }

            free(thread_new_centers);
            free(thread_new_centers_len);
        } // End of parallel region for assignment and summation

        // Update cluster centers
        for (i = 0; i < nclusters; i++) {
            if (new_centers_len[i] > 0) {
                for (j = 0; j < nfeatures; j++) {
                    new_centers[i][j] = block_new_centers[i * nfeatures + j] / new_centers_len[i];
                }
            } else {
                // Handle empty clusters: re-initialize center (e.g., pick a random point)
                // For simplicity, we'll just re-initialize with a random point from the dataset.
                // This is a common strategy to prevent empty clusters.
                int random_point_idx = rand() % npoints;
                for(j=0; j<nfeatures; ++j) {
                    new_centers[i][j] = feature[random_point_idx][j];
                }
            }
        }

        // Copy new membership to the old one for the next iteration's comparison
        memcpy(membership, membership_new, npoints * sizeof(int));

        // Free temporary count array
        free(new_centers_len);

        loop++;

    } while (delta > threshold && loop < 1000); // Add a loop limit to prevent infinite loops

    // Free memory allocated for temporary cluster centers
    // The final cluster centers are returned.

    return new_centers;
}
